        <div style={{ display: 'block' }}>
            <DsplL bold={false}>DsplL</DsplL>
            <DsplL>DsplL Bold</DsplL>
            <DsplL medium>DsplL Medium</DsplL>
            <DsplM bold={false}>DsplM</DsplM>
